    return T;
}

// src/main.cpp
#include "kinematics.h"
#include <iostream>
int main() {
    ForwardKinematics fk;
    Eigen::VectorXd q(6);
    q << 0, M_PI/4, -M_PI/3, 0, M_PI/2, 0;
    auto T = fk.compute(q);
    std::cout << "末端位姿:\n" << T << std::endl;
