**2. ROS2 C++ Publisher**

```cpp
// src/joint_publisher.cpp
#include <rclcpp/rclcpp.hpp>
#include <sensor_msgs/msg/joint_state.hpp>
#include <cmath>

class JointPublisher : public rclcpp::Node {
public:
    JointPublisher() : Node("joint_publisher"), t_(0.0) {
        pub_ = create_publisher<sensor_msgs::msg::JointState>(
            "/joint_states", 10);
        timer_ = create_wall_timer(
            std::chrono::milliseconds(10),  // 100Hz
            [this]() { publish_joints(); });
    }
private:
    void publish_joints() {
        auto msg = sensor_msgs::msg::JointState();
        msg.header.stamp = now();
        msg.name = {"joint1", "joint2", "joint3"};
        msg.position = {sin(t_), cos(t_) * 0.5, sin(t_ * 2)};
        pub_->publish(msg);
        t_ += 0.01;
    }
    rclcpp::Publisher<sensor_msgs::msg::JointState>::SharedPtr pub_;
    rclcpp::TimerBase::SharedPtr timer_;
    double t_;
};

int main(int argc, char* argv[]) {
    rclcpp::init(argc, argv);
    rclcpp::spin(std::make_shared<JointPublisher>());
    rclcpp::shutdown();
}
```

**3. CMake + pybind11 Python 绑定**

```cmake
# CMakeLists.txt (增加 pybind11 绑定)
find_package(pybind11 REQUIRED)

pybind11_add_module(pykinematics src/bindings.cpp)
target_link_libraries(pykinematics PRIVATE kinematics)
```

```cpp
// src/bindings.cpp
#include <pybind11/pybind11.h>
#include <pybind11/eigen.h>
#include "kinematics.h"

namespace py = pybind11;

PYBIND11_MODULE(pykinematics, m) {
    py::class_<ForwardKinematics>(m, "ForwardKinematics")
        .def(py::init<>())
        .def("compute", &ForwardKinematics::compute);
}

// Python 中使用:
// from pykinematics import ForwardKinematics
// fk = ForwardKinematics()
// T = fk.compute(np.array([0, 0.5, -0.3, 0, 1.0, 0]))
```
